import React from 'react';
import { Link } from 'react-router-dom';

const Navbar = () => (
  <nav className="bg-sriLanka-orange text-white px-6 py-4 shadow-md flex items-center justify-between">
    <div className="font-bold text-xl">
      Janaya360
    </div>
    <div className="flex space-x-6">
      <Link to="/" className="hover:text-sriLanka-maroon transition">Home</Link>
      <Link to="/politicians" className="hover:text-sriLanka-maroon transition">Politicians</Link>
      <Link to="/promises" className="hover:text-sriLanka-maroon transition">Promises</Link>
      <Link to="/feedback" className="hover:text-sriLanka-maroon transition">Feedback</Link>
      <Link to="/news" className="hover:text-sriLanka-maroon transition">News</Link>
      <Link to="/notifications" className="hover:text-sriLanka-maroon transition">Notifications</Link>
    </div>
  </nav>
);

export default Navbar;
